import{_ as a,o as r,c as s,a2 as i}from"./chunks/framework.Crpw6aS5.js";const d=JSON.parse('{"title":"Archivage","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/archiving.md","filePath":"fr/guide/archiving.md"}'),t={name:"fr/guide/archiving.md"};function l(o,e,n,u,c,p){return r(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="archivage" tabindex="-1">Archivage <a class="header-anchor" href="#archivage" aria-label="Permalink to &quot;Archivage&quot;">​</a></h1><p>Nid vous permet de sauvegarder vos mails sur votre NAS au format <strong>EML</strong> (un fichier par mail). Les archives sont indexées dans PostgreSQL pour une recherche rapide.</p><hr><h2 id="pourquoi-archiver" tabindex="-1">Pourquoi archiver ? <a class="header-anchor" href="#pourquoi-archiver" aria-label="Permalink to &quot;Pourquoi archiver ?&quot;">​</a></h2><ul><li><strong>Libérer votre quota Gmail</strong> : supprimez les mails de Gmail après les avoir archivés localement</li><li><strong>Sauvegarde durable</strong> : les fichiers EML sont au format standard, lisibles par n&#39;importe quel client mail (Thunderbird, Outlook, etc.)</li><li><strong>Recherche rapide</strong> : les archives sont indexées en full-text dans PostgreSQL</li><li><strong>Vos données chez vous</strong> : aucune donnée ne quitte votre réseau</li></ul><hr><h2 id="archiver-des-mails" tabindex="-1">Archiver des mails <a class="header-anchor" href="#archiver-des-mails" aria-label="Permalink to &quot;Archiver des mails&quot;">​</a></h2><h3 id="archivage-par-selection" tabindex="-1">Archivage par sélection <a class="header-anchor" href="#archivage-par-selection" aria-label="Permalink to &quot;Archivage par sélection&quot;">​</a></h3><ol><li>Dans <strong>Mes mails</strong>, sélectionnez les mails à archiver</li><li>Cliquez sur <strong>Archiver sur NAS</strong> dans la barre d&#39;actions</li><li>Un job d&#39;archivage est créé avec suivi en temps réel</li></ol><h3 id="archivage-par-requete-tout-archiver" tabindex="-1">Archivage par requête (tout archiver) <a class="header-anchor" href="#archivage-par-requete-tout-archiver" aria-label="Permalink to &quot;Archivage par requête (tout archiver)&quot;">​</a></h3><ol><li>Dans <strong>Mes mails</strong>, saisez une requête de recherche (ex. <code>from:amazon.fr older_than:6m</code>)</li><li>Cliquez sur <strong>Tout archiver</strong></li><li>Tous les mails correspondants sont archivés en différentiel</li></ol><h3 id="archivage-differentiel" tabindex="-1">Archivage différentiel <a class="header-anchor" href="#archivage-differentiel" aria-label="Permalink to &quot;Archivage différentiel&quot;">​</a></h3><p>L&#39;archivage est <strong>différentiel</strong> par défaut : seuls les mails qui n&#39;ont pas encore été archivés sont traités. Si vous archivez deux fois la même requête, la deuxième exécution ne traite que les nouveaux mails.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : bouton &quot;Tout archiver&quot; sur la page Mes mails</em></p></blockquote><hr><h2 id="consulter-les-archives" tabindex="-1">Consulter les archives <a class="header-anchor" href="#consulter-les-archives" aria-label="Permalink to &quot;Consulter les archives&quot;">​</a></h2><p>La page <strong>Archives</strong> dans la sidebar affiche tous vos mails archivés.</p><h3 id="recherche-full-text" tabindex="-1">Recherche full-text <a class="header-anchor" href="#recherche-full-text" aria-label="Permalink to &quot;Recherche full-text&quot;">​</a></h3><p>La barre de recherche permet une <strong>recherche full-text</strong> dans vos archives. La recherche porte sur :</p><ul><li><strong>L&#39;objet du mail</strong> (priorité la plus haute)</li><li><strong>L&#39;expéditeur</strong> (priorité moyenne)</li><li><strong>Le contenu</strong> du mail (extrait/snippet, priorité la plus basse)</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Archives avec la barre de recherche full-text et les résultats</em></p></blockquote><h3 id="tri-et-filtres" tabindex="-1">Tri et filtres <a class="header-anchor" href="#tri-et-filtres" aria-label="Permalink to &quot;Tri et filtres&quot;">​</a></h3><p>Vous pouvez trier les archives par :</p><ul><li>Date (plus récent / plus ancien)</li><li>Taille (plus gros / plus petit)</li><li>Expéditeur</li></ul><h3 id="lecture-d-un-mail-archive" tabindex="-1">Lecture d&#39;un mail archivé <a class="header-anchor" href="#lecture-d-un-mail-archive" aria-label="Permalink to &quot;Lecture d&#39;un mail archivé&quot;">​</a></h3><p>Cliquez sur un mail archivé pour l&#39;ouvrir dans le lecteur intégré. Le contenu est lu directement depuis le fichier EML sur le disque.</p><p>Si le mail est <strong>chiffré</strong>, il sera déchiffré à la volée (vous devrez avoir configuré votre passphrase — voir <a href="./privacy.html#chiffrement-des-archives">Vie privée</a>).</p><h3 id="vue-par-conversations-threads" tabindex="-1">Vue par conversations (threads) <a class="header-anchor" href="#vue-par-conversations-threads" aria-label="Permalink to &quot;Vue par conversations (threads)&quot;">​</a></h3><p>Les archives supportent la vue <strong>conversations</strong> : les mails partageant le même thread sont regroupés. Basculez entre la vue liste et la vue conversations avec le toggle en haut de la page.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : toggle liste/conversations sur la page Archives</em></p></blockquote><hr><h2 id="pieces-jointes-archivees" tabindex="-1">Pièces jointes archivées <a class="header-anchor" href="#pieces-jointes-archivees" aria-label="Permalink to &quot;Pièces jointes archivées&quot;">​</a></h2><p>Les pièces jointes sont extraites et stockées séparément lors de l&#39;archivage. Vous pouvez les télécharger individuellement depuis :</p><ul><li>Le lecteur de mail archivé</li><li>La page <strong>Pièces jointes</strong> (onglet Archives)</li></ul><hr><h2 id="export-zip" tabindex="-1">Export ZIP <a class="header-anchor" href="#export-zip" aria-label="Permalink to &quot;Export ZIP&quot;">​</a></h2><p>Exportez une sélection de mails archivés au format ZIP :</p><ol><li>Dans <strong>Archives</strong>, sélectionnez les mails à exporter</li><li>Cliquez sur <strong>Exporter en ZIP</strong></li><li>Un fichier ZIP contenant les fichiers EML est téléchargé</li></ol><hr><h2 id="organisation-sur-le-disque" tabindex="-1">Organisation sur le disque <a class="header-anchor" href="#organisation-sur-le-disque" aria-label="Permalink to &quot;Organisation sur le disque&quot;">​</a></h2><p>Les archives sont organisées sur le NAS selon la structure suivante :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/archives/</span></span>
<span class="line"><span>└── {account_id}/</span></span>
<span class="line"><span>    └── {année}/</span></span>
<span class="line"><span>        └── {mois}/</span></span>
<span class="line"><span>            ├── {message_id}.eml</span></span>
<span class="line"><span>            └── attachments/</span></span>
<span class="line"><span>                ├── facture.pdf</span></span>
<span class="line"><span>                └── photo.jpg</span></span></code></pre></div><p>Chaque mail est identifié par un UUID unique (le <code>gmail_message_id</code>).</p><hr><h2 id="corbeille-des-archives" tabindex="-1">Corbeille des archives <a class="header-anchor" href="#corbeille-des-archives" aria-label="Permalink to &quot;Corbeille des archives&quot;">​</a></h2><p>Les mails archivés peuvent être supprimés via la <strong>corbeille</strong>. La suppression est un <strong>soft-delete</strong> : les mails ne sont pas immédiatement effacés du disque.</p><h3 id="supprimer-des-archives" tabindex="-1">Supprimer des archives <a class="header-anchor" href="#supprimer-des-archives" aria-label="Permalink to &quot;Supprimer des archives&quot;">​</a></h3><ol><li>Dans <strong>Archives</strong>, sélectionnez les mails à supprimer</li><li>Cliquez sur <strong>Supprimer</strong> dans la barre d&#39;actions</li><li>Confirmez la suppression — les mails sont déplacés vers la corbeille</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : bouton Supprimer et confirmation dans la barre d&#39;actions des archives</em></p></blockquote><h3 id="consulter-la-corbeille" tabindex="-1">Consulter la corbeille <a class="header-anchor" href="#consulter-la-corbeille" aria-label="Permalink to &quot;Consulter la corbeille&quot;">​</a></h3><p>Basculez vers l&#39;onglet <strong>Corbeille</strong> (à côté de Liste et Conversations) pour voir les mails supprimés :</p><ul><li>Chaque mail affiche sa <strong>date de suppression</strong> et le <strong>temps restant</strong> avant la purge définitive</li><li>Un indicateur couleur signale les mails proches de l&#39;expiration (rouge ≤ 3 jours, orange ≤ 7 jours)</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : onglet Corbeille avec les indicateurs d&#39;expiration</em></p></blockquote><h3 id="restaurer-des-mails" tabindex="-1">Restaurer des mails <a class="header-anchor" href="#restaurer-des-mails" aria-label="Permalink to &quot;Restaurer des mails&quot;">​</a></h3><ol><li>Dans l&#39;onglet <strong>Corbeille</strong>, sélectionnez les mails à restaurer</li><li>Cliquez sur <strong>Restaurer</strong> dans la barre d&#39;actions</li><li>Les mails retrouvent leur place dans les archives</li></ol><p>Vous pouvez aussi restaurer un mail individuel en cliquant sur l&#39;icône de restauration dans sa ligne.</p><h3 id="vider-la-corbeille" tabindex="-1">Vider la corbeille <a class="header-anchor" href="#vider-la-corbeille" aria-label="Permalink to &quot;Vider la corbeille&quot;">​</a></h3><p>Le bouton <strong>Vider la corbeille</strong> supprime <strong>définitivement</strong> tous les mails de la corbeille :</p><ul><li>Les fichiers EML sont supprimés du disque</li><li>Les pièces jointes associées sont supprimées</li><li>Les enregistrements sont supprimés de la base de données</li><li><strong>Cette action est irréversible</strong></li></ul><h3 id="purge-automatique" tabindex="-1">Purge automatique <a class="header-anchor" href="#purge-automatique" aria-label="Permalink to &quot;Purge automatique&quot;">​</a></h3><p>Un job planifié purge automatiquement les mails en corbeille depuis plus de <strong>30 jours</strong> (par défaut). Ce job s&#39;exécute quotidiennement à 4h du matin.</p><p>Vous pouvez configurer la purge depuis la page <strong>Jobs</strong> :</p><ul><li><strong>Activer/désactiver</strong> la purge automatique</li><li><strong>Modifier la durée</strong> de rétention (1 à 365 jours)</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : section configuration corbeille dans la page Jobs</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Conseil</p><p>Si vous supprimez accidentellement des mails importants, vous pouvez les restaurer tant qu&#39;ils n&#39;ont pas été purgés. Consultez régulièrement la corbeille pour éviter les surprises.</p></div>`,65)])])}const g=a(t,[["render",l]]);export{d as __pageData,g as default};
